        }
    }

    private boolean isPrivateIP(String ipAddress) {
        // Check for private IP ranges
        return ipAddress.startsWith("10.") ||
               ipAddress.startsWith("192.168.") ||
               (ipAddress.startsWith("172.") && isInPrivateRange172(ipAddress)) ||
               ipAddress.startsWith("fc00:") || // IPv6 private
               ipAddress.startsWith("fd00:");   // IPv6 private
